import {
    AvailableModel,
    CreateChatCompletionOptions,
    LLMClient,
} from "@browserbasehq/stagehand";
import OpenAI from "openai";
import { zodResponseFormat } from "openai/helpers/zod";
import type {
    ChatCompletion,
    ChatCompletionAssistantMessageParam,
    ChatCompletionContentPartImage,
    ChatCompletionContentPartText,
    ChatCompletionCreateParamsNonStreaming,
    ChatCompletionMessageParam,
    ChatCompletionSystemMessageParam,
    ChatCompletionUserMessageParam,
} from "openai/resources/chat/completions";
import { z } from "zod/v3";
// import { CreateChatCompletionResponseError } from "../types/stagehandErrors.js";
import { CreateChatCompletionResponseError } from "@browserbasehq/stagehand";

// 专门针对 qwen-vl-plus 返回结构的 Zod Schema，确保其符合 Stagehand 的 CreateChatCompletionResponse 要求
const QwenResponseSchema = z.object({
    choices: z.array(
      z.object({
        message: z.object({
          role: z.enum(["assistant", "user", "system"]),
          content: z.string(),
        }),
      })
    ),
    model: z.string(),
    created: z.number().optional(), // 兼容 OpenAI 字段
    usage: z.object({
      prompt_tokens: z.number().optional(),
      completion_tokens: z.number().optional(),
    }).optional(),
  });
// 对模型返回的数据进行验证-在stagehand源码里贴的
