//     }
// }
//优化一下原有的适配逻辑
function validateZodSchema(schema: z.ZodTypeAny, data: unknown) {
    // Step 1: 基础校验（保持原有逻辑）
    const parsed = schema.safeParse(data);
    if (!parsed.success) {
      return false; // 保持与原函数一致的返回类型
    }

    // Step 2: 动态适配 qwen-vl-plus 响应结构（新增逻辑）
    if (isQwenVlPlusResponse(data)) {
      const adapted = adaptQwenResponse(data); // 调用内部适配器
      return schema.safeParse(adapted).success; // 二次校验
    }

    return true;
  }

  // 辅助函数：判断是否为 qwen-vl-plus 响应
  function isQwenVlPlusResponse(data: any): boolean {
    return data?.model?.includes("qwen-vl-plus") && Array.isArray(data?.choices);
  }

  // 内部适配器（不暴露给外部）
  function adaptQwenResponse(response: any) {
    return {
      choices: response.choices.map((choice: any) => ({
        message: {
          role: choice.message?.role || "assistant",
          content: choice.message?.content || "",
        },
      })),
      model: response.model,
      created: response.created || Math.floor(Date.now() / 1000),
    };
  }
