  }

  const textContent: ChatCompletionContentPartText = {
    text: content.text, // 类型收窄为 string
    type: "text"
  };
  return textContent;
}
                    });

                    if (message.role === "system") {
                        const formattedMessage: ChatCompletionSystemMessageParam = {
                            ...message,
