 */
export class CustomOpenAIClient extends LLMClient {
  type = "openai";
  client;
  modelName;

  constructor({ modelName, client }) {
    super(modelName);
    this.client = client;
    this.modelName = modelName;
  }

  /**
   * This is the core method Stagehand calls to interact with the LLM.
   * @param {object} options - The options for the chat completion.
   * @returns {Promise<object>} The response from the LLM, formatted for Stagehand.
   */
  async createChatCompletion({ options }) {
    const { messages } = options;

    const body = {
      messages: messages,
      model: this.modelName,
      stream: false,
    };

    try {
        const response = await this.client.chat.completions.create(body);

        // Return the specific format that Stagehand expects
        return {
          data: response.choices[0].message.content,
          usage: {
            prompt_tokens: response.usage?.prompt_tokens ?? 0,
            completion_tokens: response.usage?.completion_tokens ?? 0,
            total_tokens: response.usage?.total_tokens ?? 0,
          },
        };
    } catch (error) {
        console.error("Error in CustomOpenAIClient:", error);
        throw error;
    }
  }
}
