  const { data: response } = await this.llmClient.createChatCompletion<OperatorResponse>({
    // ... existing code
  });

  // Add logging here
  if (this.stagehand.logInferenceToFile) {
    writeTimestampedTxtFile(
      "agent_summary", 
      "agent_decision",
      {
        step: currentStep,
        decision: response,
        timestamp: new Date().toISOString()
      }
    );
  }

  return response;
}
```

